The proxy configuration redirects API calls to your local Fiber nodes. Adjust the ports to match your node configuration.

## Implementing the Fiber Integration

### 1. Create the Fiber RPC Class

Most interaction with the Fiber network is done through the RPC API. So let's create a wrapper for the Fiber RPC API in our typescript project.

We'll use `@ckb-ccc/fiber` from `@ckb-ccc/core` to help us create the RPC client.

First, install the dependencies:

```bash
pnpm add @ckb-ccc/fiber@0.0.0-canary-20260505020844
```

### 2. Create the FiberNode Class

Next, create a helper class to manage Fiber node operations at `src/fiber/node.ts`:

<details>
<summary>View full code of src/fiber/node.ts</summary>

```typescript
import { FiberSDK } from "@ckb-ccc/fiber";

export class FiberNode {
  public readonly sdk: FiberSDK;

  constructor(
    public readonly url: string,
    public readonly pubkey: string,
    public readonly address: string,
  ) {
    this.sdk = new FiberSDK({ endpoint: url });
  }

private generateRandomPaymentPreimage() {
    const bytes = crypto.getRandomValues(new Uint8Array(32));
    return `0x${Array.from(bytes)
      .map((b) => b.toString(16).padStart(2, "0"))
      .join("")}`;
  }

  async createCKBInvoice(amount: string, description: string) {
    const paymentPreimage = this.generateRandomPaymentPreimage();
    return await this.sdk.newInvoice({
      amount,
      currency: "Fibt",
      description,
      expiry: "0xe10",
      paymentPreimage,
    });
  }

  async sendPayment(invoice: string) {
    return await this.sdk.sendPayment({ invoice });
  }
}
```

</details>

### 3. Create Fiber Integration Main Module

Now, create the main Fiber integration file at `src/fiber/index.ts`:

<details>
<summary>View full code of src/fiber/index.ts</summary>

```typescript
import { FiberNode } from "./node";

export const amountPerPoint = 1 * 10 ** 8; // 1 CKB per point

const node1 = {
  pubkey:
    "0x02aa3beb0d770fe835db99bf894fb2d9afaf4df0d5ec1871fad731d4fc6c90faed",
  address:
    "/ip4/127.0.0.1/tcp/8228/p2p/QmUTsrLgHnoFenNbSFQyYAmAFxi3ZPkxAVnqJ8e9hhzeSm",
  url: "/node1-api",
};

const node2 = {
  pubkey:
    "0x03827ccddf3fdf59808fa6baea647d93bd6f6105309d3b20e1fc0d9e40495865cc",
  address:
    "/ip4/127.0.0.1/tcp/8238/p2p/QmTUyCohdeaWyPVSeQg5uWiTG8ztZ2rwBXP7PUZPk5Qc2w",
  url: "/node2-api",
};

export async function prepareNodes() {
  const bossNode = new FiberNode(node1.url, node1.pubkey, node1.address);
  const playerNode = new FiberNode(node2.url, node2.pubkey, node2.address);
  console.log("bossNode", bossNode);
  console.log("playerNode", playerNode);

  await bossNode.sdk.connectPeer({
    address: playerNode.address,
  });

  const channels = await bossNode.sdk.listChannels({
    pubkey: playerNode.pubkey,
  });
  const activeChannel = channels.filter(
    (channel) => channel.state.stateName === "CHANNEL_READY",
  );
  console.log("activeChannel", activeChannel);
  return { bossNode, playerNode };
}

export async function payPlayerPoints(
  bossNode: FiberNode,
  playerNode: FiberNode,
  points: number,
) {
  const amount = `0x${(amountPerPoint * points).toString(16)}`;

const invoice = await playerNode.createCKBInvoice(
    amount,
    "player hit the boss!",
  );
  const result = await bossNode.sendPayment(invoice.invoiceAddress);
  console.log(`boss pay player ${points} CKB`);
  console.log("invoice", invoice);
  console.log("payment result", result);
}

export async function payBossPoints(
  bossNode: FiberNode,
  playerNode: FiberNode,
  points: number,
) {
  const amount = `0x${(amountPerPoint * points).toString(16)}`;
  const invoice = await bossNode.createCKBInvoice(
    amount,
    "boss hit the player!",
  );
  const result = await playerNode.sendPayment(invoice.invoiceAddress);
  console.log(`player pay boss ${points} CKB`);
  console.log("invoice", invoice);
  console.log("payment result", result);
}
```

</details>

